}

.hljs-keyword,
.hljs-selector-tag,
.hljs-built_in,
.hljs-name,
.hljs-tag {
  color: var(--color-syntax-keyword);
}

.hljs-string,
.hljs-title,
.hljs-section,
.hljs-attribute,
.hljs-literal,
.hljs-template-tag,
.hljs-template-variable,
.hljs-type,
.hljs-addition {
  color: var(--color-syntax-string);
}

.hljs-deletion,
.hljs-selector-attr,
.hljs-selector-pseudo,
.hljs-meta {
  color: var(--color-syntax-meta);
}

.hljs-doctag,
.hljs-attr {
  color: var(--color-syntax-attr);
}

.hljs-symbol,
.hljs-bullet,
.hljs-link,
.hljs-subst,
.hljs-variable,
.hljs-number,
.hljs-regexp {
  color: var(--color-syntax-number);
}

.hljs-emphasis {
  font-style: italic;
}

.hljs-strong {
  font-weight: bold;
}

/* Link preview tooltip */
.link-preview-tooltip {
  position: fixed;
  z-index: 1000;
  display: none;
  max-width: 360px;
  background: var(--color-surface-subtle);
  border: 1px solid var(--color-border-strong);
  border-radius: 6px;
  padding: 5px 10px;
  font-size: 12px;
  font-family: var(--font-ui);
  color: var(--color-fg-muted);
  pointer-events: none;
  box-shadow: 0 4px 12px var(--shadow-tooltip);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

