input.content:
.find-replace-bar {
  position: absolute;
  top: 12px;
  right: 24px;
  z-index: 100;
  width: 340px;
  background: var(--color-surface);
  border: 1px solid var(--color-border-strong);
  border-radius: 8px;
  box-shadow:
    0 4px 20px rgba(0, 0, 0, 0.12),
    0 1px 4px rgba(0, 0, 0, 0.08);
  padding: 8px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.find-replace-row {
  display: flex;
  align-items: center;
  gap: 4px;
}

.find-replace-input-wrap {
  position: relative;
  flex: 1;
}

.find-replace-input {
  width: 100%;
  height: 28px;
  padding: 0 8px;
  font-size: 13px;
  font-family: var(--font-ui);
  color: var(--color-fg);
  background: var(--color-surface-subtle);
  border: 1px solid var(--color-border);
  border-radius: 5px;
  outline: none;
  box-sizing: border-box;
  transition: border-color 0.15s;
}

/* Second row replace input spans the input wrap width */
.find-replace-row:last-child .find-replace-input {
  flex: 1;
}

.find-replace-input:focus {
  border-color: var(--color-accent);
}

.find-replace-count {
  position: absolute;
  right: 6px;
  top: 50%;
  transform: translateY(-50%);
  font-size: 11px;
  font-family: var(--font-ui);
  color: var(--color-fg-subtle);
  pointer-events: none;
  white-space: nowrap;
}

/* Nudge the input text left so it doesn't overlap the count */
.find-replace-input-wrap .find-replace-input {
  padding-right: 60px;
}

.find-replace-nav-btn,
.find-replace-close-btn {
  flex-shrink: 0;
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  border: none;
  border-radius: 5px;
  background: transparent;
  color: var(--color-fg-muted);
  cursor: pointer;
  font-size: 14px;
  transition:
    background 0.12s,
    color 0.12s;
}

.find-replace-nav-btn:hover,
.find-replace-close-btn:hover {
  background: var(--color-surface-hover);
  color: var(--color-fg);
}

.find-replace-nav-btn:disabled {
  color: var(--color-fg-subtle);
  cursor: default;
}

.find-replace-nav-btn:disabled:hover {
  background: transparent;
}

.find-replace-close-btn {
  font-size: 18px;
  color: var(--color-fg-subtle);
}

.find-replace-action-btn {
  flex-shrink: 0;
  height: 28px;
  padding: 0 10px;
  font-size: 12px;
  font-family: var(--font-ui);
  color: var(--color-fg-muted);
  background: var(--color-surface-subtle);
  border: 1px solid var(--color-border);
  border-radius: 5px;
  cursor: pointer;
  transition:
    background 0.12s,
    color 0.12s,
    border-color 0.12s;
}

.find-replace-action-btn:hover {
  background: var(--color-surface-hover);
  color: var(--color-fg);
  border-color: var(--color-border-strong);
}

.find-replace-action-btn:disabled {
  color: var(--color-fg-subtle);
  cursor: default;
}

.find-replace-action-btn:disabled:hover {
  background: var(--color-surface-subtle);
  border-color: var(--color-border);
}

/* ── Match highlight decorations ───────────────── */
.find-match {
  background: var(--color-accent-subtle);
  border-radius: 2px;
}

.find-match-current {
  background: var(--color-accent);
  color: var(--color-surface);
  border-radius: 2px;
}

